explanation:
Classic Verilog uses `reg` for the procedural output and an event control containing both the clock edge and reset edge.

```verilog
module dff_async_reset (
  input  wire clk,
  input  wire rst_n,
  input  wire d,
  output reg  q
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      q <= 1'b0;
    else
      q <= d;
  end
endmodule
```

A synchronous reset is sampled only on the active clock edge, and the enable controls whether new data is loaded.

```verilog
always @(posedge clk) begin
  if (rst)
    q <= 1'b0;
  else if (en)
    q <= d;
end
```

Sample the previous value, then compare it with the current synchronized value.

```verilog
reg sig_d;

always @(posedge clk or negedge rst_n) begin
  if (!rst_n)
    sig_d <= 1'b0;
  else
    sig_d <= sig;
end

assign rise_pulse = sig & ~sig_d;
```

Verilog parameters can define width while the flop logic remains a normal clocked always block.

```verilog
module up_counter #(
  parameter WIDTH = 8
) (
  input  wire clk,
  input  wire rst_n,
  input  wire en,
  output reg  [WIDTH-1:0] count
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= {WIDTH{1'b0}};
    else if (en)
      count <= count + {{(WIDTH-1){1'b0}}, 1'b1};
  end
endmodule
```

A serial shift register is a vector register updated by concatenation.

```verilog
module shift_reg #(
  parameter DEPTH = 4
) (
  input  wire clk,
  input  wire rst_n,
  input  wire en,
  input  wire din,
  output reg  [DEPTH-1:0] shift
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      shift <= {DEPTH{1'b0}};
    else if (en)
      shift <= {shift[DEPTH-2:0], din};
  end
endmodule
```

The default assignment prevents latch inference and gives defined behavior for unexpected select values.

```verilog
always @* begin
  dec = 4'b0000;
  case (sel)
    2'd0: dec = 4'b0001;
    2'd1: dec = 4'b0010;
    2'd2: dec = 4'b0100;
    2'd3: dec = 4'b1000;
    default: dec = 4'b0000;
  endcase
end
```

Before SystemVerilog enums, a common Verilog FSM style used `localparam` encodings and `reg` state variables.

```verilog
localparam IDLE = 2'd0,
           RUN  = 2'd1,
           DONE = 2'd2;

reg [1:0] state_q, state_d;

always @(posedge clk or negedge rst_n) begin
  if (!rst_n) state_q <= IDLE;
  else        state_q <= state_d;
end

always @* begin
  state_d = state_q;
  done = 1'b0;
  case (state_q)
    IDLE: if (start) state_d = RUN;
    RUN:  if (last)  state_d = DONE;
    DONE: begin done = 1'b1; state_d = IDLE; end
    default: state_d = IDLE;
  endcase
end
```

A guarded loop avoids later request bits overwriting the first match.

```verilog
integer i;

always @* begin
  valid = 1'b0;
  idx = {IDX_W{1'b0}};
  for (i = 0; i < WIDTH; i = i + 1) begin
    if (!valid && req[i]) begin
      valid = 1'b1;
      idx = i[IDX_W-1:0];
    end
  end
end
```

A small inferred register file can use a Verilog unpacked memory array, synchronous writes, and continuous read assignments.

```verilog
reg [WIDTH-1:0] mem [0:DEPTH-1];

always @(posedge clk) begin
  if (we)
    mem[waddr] <= wdata;
end

assign rdata0 = mem[raddr0];
assign rdata1 = mem[raddr1];
```

Register the previous value of `sig`, then compare the current sample against the delayed sample.

```verilog
module edge_detect (
    input  wire clk,
    input  wire rst_n,
    input  wire sig,
    output wire rise_pulse
);

    reg sig_d;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sig_d <= 1'b0;
        else
            sig_d <= sig;
    end

    assign rise_pulse = sig & ~sig_d;

endmodule
```

Reset has priority. The enable controls whether the flop samples `d` on a clock edge.

```verilog
module dff_en (
    input  wire clk,
    input  wire rst_n,
    input  wire en,
    input  wire d,
    output reg  q
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            q <= 1'b0;
        else if (en)
            q <= d;
    end

endmodule
```

The first destination-domain flop may go metastable, and the second flop reduces the probability that metastability propagates.

```verilog
module two_flop_sync (
    input  wire clk_dst,
    input  wire rst_n,
    input  wire async_sig,
    output wire sync_sig
);

    reg sync_ff1;
    reg sync_ff2;

    always @(posedge clk_dst or negedge rst_n) begin
        if (!rst_n) begin
            sync_ff1 <= 1'b0;
            sync_ff2 <= 1'b0;
        end else begin
            sync_ff1 <= async_sig;
            sync_ff2 <= sync_ff1;
        end
    end

    assign sync_sig = sync_ff2;

endmodule
```

A one-cycle source pulse may be too short for the destination clock to sample. A toggle holds the event as a level change until the destination domain captures it.

```verilog
module pulse_sync (
    input  wire clk_src,
    input  wire rst_src_n,
    input  wire pulse_src,

    input  wire clk_dst,
    input  wire rst_dst_n,
    output wire pulse_dst
);

    reg toggle_src;

    always @(posedge clk_src or negedge rst_src_n) begin
        if (!rst_src_n)
            toggle_src <= 1'b0;
        else if (pulse_src)
            toggle_src <= ~toggle_src;
    end

    reg sync1, sync2, sync3;

    always @(posedge clk_dst or negedge rst_dst_n) begin
        if (!rst_dst_n) begin
            sync1 <= 1'b0;
            sync2 <= 1'b0;
            sync3 <= 1'b0;
        end else begin
            sync1 <= toggle_src;
            sync2 <= sync1;
            sync3 <= sync2;
        end
    end

    assign pulse_dst = sync2 ^ sync3;

endmodule
```

The counter width is controlled by a parameter, and the enable gates the count update.

```verilog
module counter #(
    parameter WIDTH = 8
)(
    input  wire             clk,
    input  wire             rst_n,
    input  wire             en,
    output reg [WIDTH-1:0]  count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            count <= {WIDTH{1'b0}};
        else if (en)
            count <= count + 1'b1;
    end

endmodule
```

A saturating counter increments until it reaches all ones, then holds that value instead of wrapping.

```verilog
module sat_counter #(
    parameter WIDTH = 8
)(
    input  wire             clk,
    input  wire             rst_n,
    input  wire             en,
    output reg [WIDTH-1:0]  count
);

    wire [WIDTH-1:0] max_value = {WIDTH{1'b1}};

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            count <= {WIDTH{1'b0}};
        else if (en && count != max_value)
            count <= count + 1'b1;
    end

endmodule
```

In a valid-ready protocol, the transaction is accepted only when both sides agree in the same cycle.

```verilog
module throughput_counter #(
    parameter WIDTH = 32
)(
    input  wire             clk,
    input  wire             rst_n,
    input  wire             valid,
    input  wire             ready,
    output reg [WIDTH-1:0]  trans_count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            trans_count <= {WIDTH{1'b0}};
        else if (valid && ready)
            trans_count <= trans_count + 1'b1;
    end

endmodule
```

This counter measures backpressure cycles on a valid-ready interface.

```verilog
module stall_counter #(
    parameter WIDTH = 32
)(
    input  wire             clk,
    input  wire             rst_n,
    input  wire             valid,
    input  wire             ready,
    output reg [WIDTH-1:0]  stall_count
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            stall_count <= {WIDTH{1'b0}};
        else if (valid && !ready)
            stall_count <= stall_count + 1'b1;
    end

endmodule
```

This simple monitor assumes only one outstanding transaction. A real design with multiple outstanding requests would need IDs, queues, or timestamp storage.

```verilog
module latency_monitor #(
    parameter WIDTH = 32
)(
    input  wire             clk,
    input  wire             rst_n,
    input  wire             start,
    input  wire             done,
    output reg [WIDTH-1:0]  latency,
    output reg              latency_valid
);

    reg [WIDTH-1:0] cycle_count;
    reg [WIDTH-1:0] start_cycle;
    reg             active;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cycle_count   <= {WIDTH{1'b0}};
            start_cycle   <= {WIDTH{1'b0}};
            latency       <= {WIDTH{1'b0}};
            latency_valid <= 1'b0;
            active        <= 1'b0;
        end else begin
            cycle_count   <= cycle_count + 1'b1;
            latency_valid <= 1'b0;

            if (start && !active) begin
                start_cycle <= cycle_count;
                active      <= 1'b1;
            end

            if (done && active) begin
                latency       <= cycle_count - start_cycle;
                latency_valid <= 1'b1;
                active        <= 1'b0;
            end
        end
    end

endmodule
```

This FIFO uses one extra pointer bit to distinguish full from empty. In production, `ADDR_WIDTH` should match `DEPTH` and reset/read-during-write behavior should be defined carefully.

```verilog
module sync_fifo #(
    parameter WIDTH = 8,
    parameter DEPTH = 16,
    parameter ADDR_WIDTH = 4
)(
    input  wire                  clk,
    input  wire                  rst_n,

    input  wire                  wr_en,
    input  wire [WIDTH-1:0]      wr_data,
    input  wire                  rd_en,
    output reg  [WIDTH-1:0]      rd_data,

    output wire                  full,
    output wire                  empty
);

    reg [WIDTH-1:0] mem [0:DEPTH-1];

    reg [ADDR_WIDTH:0] wr_ptr;
    reg [ADDR_WIDTH:0] rd_ptr;

    assign empty = (wr_ptr == rd_ptr);
    assign full  = (wr_ptr[ADDR_WIDTH] != rd_ptr[ADDR_WIDTH]) &&
                   (wr_ptr[ADDR_WIDTH-1:0] == rd_ptr[ADDR_WIDTH-1:0]);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr  <= {(ADDR_WIDTH+1){1'b0}};
            rd_ptr  <= {(ADDR_WIDTH+1){1'b0}};
            rd_data <= {WIDTH{1'b0}};
        end else begin
            if (wr_en && !full) begin
                mem[wr_ptr[ADDR_WIDTH-1:0]] <= wr_data;
                wr_ptr <= wr_ptr + 1'b1;
            end

            if (rd_en && !empty) begin
                rd_data <= mem[rd_ptr[ADDR_WIDTH-1:0]];
                rd_ptr <= rd_ptr + 1'b1;
            end
        end
    end

endmodule
```

The FSM separates state update, counter update, next-state decode, and output decode.

```verilog
module simple_fsm (
    input  wire clk,
    input  wire rst_n,
    input  wire start,
    output reg  busy,
    output reg  done
);

    localparam IDLE = 2'd0;
    localparam RUN  = 2'd1;
    localparam DONE = 2'd2;

    reg [1:0] state, next_state;
    reg [2:0] count;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            state <= IDLE;
        else
            state <= next_state;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            count <= 3'd0;
        else if (state == RUN)
            count <= count + 1'b1;
        else
            count <= 3'd0;
    end

    always @(*) begin
        next_state = state;

        case (state)
            IDLE: begin
                if (start)
                    next_state = RUN;
            end

            RUN: begin
                if (count == 3'd3)
                    next_state = DONE;
            end

            DONE: begin
                next_state = IDLE;
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    always @(*) begin
        busy = 1'b0;
        done = 1'b0;

        case (state)
            RUN: begin
                busy = 1'b1;
            end

            DONE: begin
                done = 1'b1;
            end
        endcase
    end

endmodule
```

A balanced tree has less combinational depth than a serial chain like `((((a+b)+c)+d)+...)`.

```verilog
module adder_tree_8 (
    input  wire signed [15:0] in0,
    input  wire signed [15:0] in1,
    input  wire signed [15:0] in2,
    input  wire signed [15:0] in3,
    input  wire signed [15:0] in4,
    input  wire signed [15:0] in5,
    input  wire signed [15:0] in6,
    input  wire signed [15:0] in7,
    output wire signed [18:0] sum
);

    wire signed [16:0] s0 = in0 + in1;
    wire signed [16:0] s1 = in2 + in3;
    wire signed [16:0] s2 = in4 + in5;
    wire signed [16:0] s3 = in6 + in7;

    wire signed [17:0] s4 = s0 + s1;
    wire signed [17:0] s5 = s2 + s3;

    assign sum = s4 + s5;

endmodule
```

The pipelined version inserts registers between adder levels. It has more latency but shorter per-cycle combinational paths.

```verilog
module pipelined_adder_tree_8 (
    input  wire               clk,
    input  wire               rst_n,
    input  wire signed [15:0] in0,
    input  wire signed [15:0] in1,
    input  wire signed [15:0] in2,
    input  wire signed [15:0] in3,
    input  wire signed [15:0] in4,
    input  wire signed [15:0] in5,
    input  wire signed [15:0] in6,
    input  wire signed [15:0] in7,
    output reg  signed [18:0] sum
);

    reg signed [16:0] s0, s1, s2, s3;
    reg signed [17:0] s4, s5;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            s0  <= 17'sd0;
            s1  <= 17'sd0;
            s2  <= 17'sd0;
            s3  <= 17'sd0;
            s4  <= 18'sd0;
            s5  <= 18'sd0;
            sum <= 19'sd0;
        end else begin
            s0 <= in0 + in1;
            s1 <= in2 + in3;
            s2 <= in4 + in5;
            s3 <= in6 + in7;

            s4 <= s0 + s1;
            s5 <= s2 + s3;

            sum <= s4 + s5;
        end
    end

endmodule
```

The accumulator is wider than the product to reduce overflow risk during repeated accumulation.

```verilog
module mac (
    input  wire                 clk,
    input  wire                 rst_n,
    input  wire                 en,
    input  wire signed [7:0]    a,
    input  wire signed [7:0]    b,
    output reg  signed [31:0]   acc
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            acc <= 32'sd0;
        else if (en)
            acc <= acc + a * b;
    end

endmodule
```

Each clock shifts the previous stages forward and inserts `din` into the first stage.

```verilog
module shift_reg_4 (
    input  wire clk,
    input  wire rst_n,
    input  wire din,
    output wire dout
);

    reg [3:0] shift_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            shift_reg <= 4'b0000;
        else
            shift_reg <= {shift_reg[2:0], din};
    end

    assign dout = shift_reg[3];

endmodule
```

`casez` lets lower-priority request bits be treated as don't-care once a higher-priority bit is set.

```verilog
module priority_encoder_4 (
    input  wire [3:0] req,
    output reg  [1:0] grant_idx,
    output reg        valid
);

    always @(*) begin
        valid     = 1'b1;
        grant_idx = 2'd0;

        casez (req)
            4'b1???: grant_idx = 2'd3;
            4'b01??: grant_idx = 2'd2;
            4'b001?: grant_idx = 2'd1;
            4'b0001: grant_idx = 2'd0;
            default: valid = 1'b0;
        endcase
    end

endmodule
```

For two requesters, a single bit is enough to remember who won last time. If both request simultaneously, grant the other requester to avoid starvation.

```verilog
module rr_arbiter_2 (
    input  wire       clk,
    input  wire       rst_n,
    input  wire [1:0] req,
    output reg  [1:0] grant
);

    reg last_grant;
    // 0 means last grant was req[0]
    // 1 means last grant was req[1]

    always @(*) begin
        grant = 2'b00;

        if (req == 2'b01)
            grant = 2'b01;
        else if (req == 2'b10)
            grant = 2'b10;
        else if (req == 2'b11) begin
            if (last_grant == 1'b0)
                grant = 2'b10;
            else
                grant = 2'b01;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            last_grant <= 1'b0;
        else if (grant[0])
            last_grant <= 1'b0;
        else if (grant[1])
            last_grant <= 1'b1;
    end

endmodule
```

An async FIFO should not synchronize multi-bit data directly. Data stays in memory, while Gray-coded pointers cross clock domains.

```verilog
