assign gray = binary ^ (binary >> 1);

// Conceptual full condition:
// next write Gray pointer equals synchronized read Gray pointer
// with the top two bits inverted.

// Conceptual empty condition:
// synchronized write Gray pointer equals current read Gray pointer.
```

