A skid buffer stores one item when downstream backpressure arrives late.

```systemverilog
assign in_ready  = !full_q || out_ready;
assign out_valid = full_q ? 1'b1 : in_valid;
assign out_data  = full_q ? data_q : in_data;

always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    full_q <= 1'b0;
  end else begin
    if (in_valid && in_ready && !out_ready) begin
      full_q <= 1'b1;
      data_q <= in_data;
    end else if (out_ready) begin
      full_q <= 1'b0;
    end
  end
end
```

A one-cycle pulse can be missed by a slower clock, so the source converts it into a level change.

```systemverilog
// Source clock domain
always_ff @(posedge src_clk or negedge src_rst_n) begin
  if (!src_rst_n) toggle_q <= 1'b0;
  else if (src_pulse) toggle_q <= ~toggle_q;
end

// Destination clock domain
always_ff @(posedge dst_clk or negedge dst_rst_n) begin
  if (!dst_rst_n) sync_q <= 3'b000;
  else            sync_q <= {sync_q[1:0], toggle_q};
end

assign dst_pulse = sync_q[2] ^ sync_q[1];
```

Gray code changes one bit per increment, which makes cross-domain pointer sampling safer.

```systemverilog
function automatic logic [PTR_W-1:0] bin_to_gray(input logic [PTR_W-1:0] bin);
  return bin ^ (bin >> 1);
endfunction

function automatic logic [PTR_W-1:0] gray_to_bin(input logic [PTR_W-1:0] gray);
  logic [PTR_W-1:0] bin;
  bin[PTR_W-1] = gray[PTR_W-1];
  for (int i = PTR_W-2; i >= 0; i--) begin
    bin[i] = bin[i+1] ^ gray[i];
  end
  return bin;
endfunction
```

A half-buffer is a one-deep register with ready/valid flow control.

```systemverilog
assign in_ready  = !valid_q || out_ready;
assign out_valid = valid_q;
assign out_data  = data_q;

always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    valid_q <= 1'b0;
  end else if (in_ready) begin
    valid_q <= in_valid;
