Example: `s = ({[]})` returns `true`; `s = ([)]` returns `false` because the closing order does not match.

```cpp
bool isValid(string s) {
  unordered_map<char, char> closeToOpen = {
    {')', '('}, {']', '['}, {'}', '{'}
  };
  vector<char> st;

  for (char c : s) {
    if (!closeToOpen.count(c)) {
      st.push_back(c);
      continue;
    }

    if (st.empty() || st.back() != closeToOpen[c]) {
      return false;
    }
    st.pop_back();
  }

  return st.empty();
}
```

