Example: in a grid where `0` is open and `1` is blocked, BFS explores by distance layers, so the first visit to the target is the minimum number of steps.

```cpp
int shortestPath(vector<vector<int>>& grid) {
  int m = grid.size();
  int n = grid[0].size();
  if (grid[0][0] == 1 || grid[m - 1][n - 1] == 1) return -1;

  vector<pair<int, int>> dirs = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
  queue<tuple<int, int, int>> q;
  vector<vector<int>> seen(m, vector<int>(n, 0));

  q.push({0, 0, 0});
  seen[0][0] = 1;

  while (!q.empty()) {
    auto [r, c, dist] = q.front();
    q.pop();
    if (r == m - 1 && c == n - 1) return dist;

    for (auto [dr, dc] : dirs) {
      int nr = r + dr;
      int nc = c + dc;
      if (nr < 0 || nc < 0 || nr >= m || nc >= n) continue;
      if (seen[nr][nc] || grid[nr][nc] == 1) continue;
      seen[nr][nc] = 1;
      q.push({nr, nc, dist + 1});
    }
  }

  return -1;
}
```

