class MyQueue {
  vector<int> in;
  vector<int> out;

  void refill() {
    if (!out.empty()) return;
    while (!in.empty()) {
      out.push_back(in.back());
      in.pop_back();
    }
  }

public:
  void push(int x) {
    in.push_back(x);
  }

  int pop() {
    refill();
    int value = out.back();
    out.pop_back();
    return value;
  }

  int front() {
    refill();
    return out.back();
  }

  bool empty() const {
    return in.empty() && out.empty();
  }
};
