def count_components(n: int, edges: list[tuple[int, int]]) -> int:
    graph = [[] for _ in range(n)]
    for a, b in edges:
        graph[a].append(b)
        graph[b].append(a)

    seen = set()

    def dfs(node: int) -> None:
        seen.add(node)
        for nxt in graph[node]:
            if nxt not in seen:
                dfs(nxt)

    components = 0
    for node in range(n):
        if node not in seen:
            components += 1
            dfs(node)

    return components
