```python
class MyQueue:
    def __init__(self) -> None:
        self._in: list[int] = []
        self._out: list[int] = []

    def _refill(self) -> None:
        if self._out:
            return
        while self._in:
            self._out.append(self._in.pop())

    def push(self, value: int) -> None:
        self._in.append(value)

    def pop(self) -> int:
        self._refill()
        return self._out.pop()

    def peek(self) -> int:
        self._refill()
        return self._out[-1]

    def empty(self) -> bool:
        return not self._in and not self._out
```

