def eval_rpn(tokens: list[str]) -> int:
    stack: list[int] = []

    for token in tokens:
        if token not in {'+', '-', '*', '/'}:
            stack.append(int(token))
            continue

        b = stack.pop()
        a = stack.pop()
        if token == '+':
            stack.append(a + b)
        elif token == '-':
            stack.append(a - b)
        elif token == '*':
            stack.append(a * b)
        else:
            stack.append(int(a / b))

    return stack[-1]
